import type { TenantId } from "./tenant.js";

declare global {
  namespace Express {
    interface Request {
      requestId: string;
      /** Set after JWT verification; omit on pre-auth routes. */
      tenantId?: TenantId;
      /** Authenticated creator id (same as tenant for this product). */
      creatorId?: string;
    }
  }
}

export {};

/** Branded string for tenant-scoped data (creator id). */
export type TenantId = string & { readonly __brand: "TenantId" };

export function toTenantId(id: string): TenantId {
  return id as TenantId;
}

import { z } from "zod";

const envSchema = z.object({
  NODE_ENV: z.enum(["development", "test", "production"]).default("development"),
  PORT: z.coerce.number().default(4000),
  LOG_LEVEL: z.enum(["fatal", "error", "warn", "info", "debug", "trace", "silent"]).default("info"),
  DATABASE_URL: z.string().url().optional()
});

export type Env = z.infer<typeof envSchema>;

export function loadEnv(): Env {
  const parsed = envSchema.safeParse(process.env);
  if (!parsed.success) {
    throw new Error(`Invalid environment: ${parsed.error.message}`);
  }
  return parsed.data;
}

import pino from "pino";
import type { Env } from "./env.js";

export function createRootLogger(env: Pick<Env, "LOG_LEVEL" | "NODE_ENV">) {
  return pino({
    level: env.LOG_LEVEL,
    base: undefined,
    formatters: {
      level(label) {
        return { level: label };
      }
    }
  });
}

import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as { prisma?: PrismaClient };

export const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    log: process.env.NODE_ENV === "development" ? ["error", "warn"] : ["error"]
  });

if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = prisma;
}

